pub enum KernelEvent {
    MergeCompleted {
        entry_id: Uuid,
        session_id: String,
        scope_id: String,
    },
    MergeFailed {
        entry_id: Uuid,
        scope_id: String,
    },
    EntryCommitted {
        entry_id: Uuid,
        session_id: String,
        scope_id: String,
    },
    SessionOpened {
        agent_id: String,
        session_id: String,
        scope_id: String,
    },
    SessionClosed {
        session_id: String,
        scope_id: String,
    },
    GcCompleted {
        scope_id: String,
        entries_removed: usize,
    },
    IngestCompleted {
        scope_id: String,
        entries_added: usize,
        duration_ms: u64,
    },
}
